import{_ as t,o as s,c as n,a2 as o}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Common Architecture Patterns","description":"Extracting the shared architectural patterns found across all major coding agents, from the agentic loop to tool dispatch.","frontmatter":{"title":"Common Architecture Patterns","description":"Extracting the shared architectural patterns found across all major coding agents, from the agentic loop to tool dispatch."},"headers":[],"relativePath":"learn/linear/01-what-is-a-coding-agent/09-common-architecture-patterns.md","filePath":"learn/linear/01-what-is-a-coding-agent/09-common-architecture-patterns.md"}'),a={name:"learn/linear/01-what-is-a-coding-agent/09-common-architecture-patterns.md"};function l(r,e,i,p,c,h){return s(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="common-architecture-patterns" tabindex="-1">Common Architecture Patterns <a class="header-anchor" href="#common-architecture-patterns" aria-label="Permalink to &quot;Common Architecture Patterns&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>The five core architectural components shared by every production coding agent</li><li>How the observe-think-act loop manifests in different agent implementations</li><li>The recurring patterns in tool design, state management, and context handling across agents</li></ul></blockquote><h2 id="the-universal-blueprint" tabindex="-1">The Universal Blueprint <a class="header-anchor" href="#the-universal-blueprint" aria-label="Permalink to &quot;The Universal Blueprint&quot;">​</a></h2><p>Over the last four subchapters, we examined four very different coding agents — Claude Code (TypeScript, terminal-native, permission-based), OpenCode (Go, terminal UI, multi-provider), Pi (Rust, type-safe, trait-based), and Codex (sandboxed, network-isolated, async). They differ in language, deployment model, UI philosophy, and safety approach.</p><p>And yet, if you squint at their architectures, they&#39;re remarkably similar.</p><p>This isn&#39;t a coincidence. The problem they&#39;re solving — connecting a language model to a development environment through an iterative loop — imposes architectural constraints that any reasonable solution must satisfy. These constraints produce a common blueprint that we can extract, study, and use as the foundation for our own agent.</p><p>Let&#39;s identify the five components that appear in every agent we&#39;ve studied.</p><h2 id="component-1-the-agentic-loop" tabindex="-1">Component 1: The Agentic Loop <a class="header-anchor" href="#component-1-the-agentic-loop" aria-label="Permalink to &quot;Component 1: The Agentic Loop&quot;">​</a></h2><p>Every coding agent has a central loop that drives execution. The specifics vary, but the structure is always the same:</p><ol><li>Construct a message for the LLM (including conversation history and tool results).</li><li>Send the message to the LLM and receive a response.</li><li>If the response contains tool calls, execute them and go to step 1 with the results.</li><li>If the response contains only text, display it to the user and wait for the next input.</li></ol><p>This is the agentic loop — the heartbeat of the system. Claude Code implements it as a recursive function that calls the API, processes tool calls, and calls itself again. OpenCode implements it as a <code>for</code> loop that checks the response type at each iteration. Pi models it as a state machine with typed transitions. Codex runs it inside a container until no more tool calls are produced.</p><p>The loop has a few critical properties:</p><p><strong>It&#39;s model-driven.</strong> The model decides whether to invoke tools or produce a final response. The runtime doesn&#39;t have a fixed number of iterations or a predetermined plan — it follows the model&#39;s lead.</p><p><strong>It&#39;s accumulative.</strong> Each iteration adds to the conversation history. The model sees everything that&#39;s happened so far — all previous messages, tool calls, and tool results — when deciding what to do next. This growing context is how the model maintains coherence across a multi-step task.</p><p><strong>It terminates naturally.</strong> The loop ends when the model produces a response without tool calls. This could mean the task is complete, the model is stuck and needs human input, or the model wants to report its progress. The runtime doesn&#39;t need explicit termination logic — the model&#39;s decision to stop calling tools is the termination signal.</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Simplified agentic loop structure</span></span>
<span class="line"><span style="color:#CBA6F7;">loop</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> llm</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">send</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Render any text content to the user</span></span>
<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> block </span><span style="color:#CBA6F7;">in</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">response</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">content </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CBA6F7;"> let</span><span style="color:#F9E2AF;font-style:italic;"> ContentBlock</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Text</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#CDD6F4;"> block </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">            ui</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">render_text</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Collect tool calls from the response</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> tool_calls</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CDD6F4;">_</span><span style="color:#89DCEB;">&gt;</span><span style="color:#94E2D5;"> =</span><span style="color:#CDD6F4;"> response</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">content</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">iter</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">filter_map</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">block</span><span style="color:#94E2D5;">|</span><span style="color:#CBA6F7;"> match</span><span style="color:#CDD6F4;"> block</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;">            ContentBlock</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">ToolUse</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tc</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Some</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tc</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#CDD6F4;">            _ </span><span style="color:#94E2D5;">=&gt;</span><span style="color:#F9E2AF;font-style:italic;"> None</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        })</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">collect</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // If no tool calls, the turn is complete</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> tool_calls</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">is_empty</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        break</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Execute tools and add results to conversation</span></span>
<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> tool_call </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> tool_calls </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> tool_dispatcher</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">execute</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tool_call</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CDD6F4;">        messages</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">Message</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">tool_result</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tool_call</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">));</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code and OpenCode both include circuit breakers in their loops — if the agent has executed an unusually large number of tool calls without completing the task, the loop pauses and asks the user whether to continue. This prevents runaway loops where the model keeps trying variations of a broken approach. Pi handles this more subtly, tracking the number of consecutive failed tool calls and prompting the user if a threshold is exceeded.</p></div><h2 id="component-2-the-llm-integration-layer" tabindex="-1">Component 2: The LLM Integration Layer <a class="header-anchor" href="#component-2-the-llm-integration-layer" aria-label="Permalink to &quot;Component 2: The LLM Integration Layer&quot;">​</a></h2><p>Every agent needs to communicate with a language model. This layer handles constructing API requests, sending them, receiving responses (often streamed), and parsing the response into a structured format the rest of the system can work with.</p><p>The key design decision here is <strong>abstraction level</strong>. Some agents hardcode a single provider (Claude Code uses the Anthropic API). Others abstract across providers (OpenCode supports Anthropic, OpenAI, Google, and local models). The level of abstraction affects flexibility, complexity, and how tightly the agent can leverage provider-specific features.</p><p>Across all agents, this layer handles:</p><ul><li><strong>Message formatting:</strong> Converting the conversation history into the format the provider&#39;s API expects.</li><li><strong>Tool schema injection:</strong> Including tool definitions in the API request so the model knows what tools are available.</li><li><strong>Response parsing:</strong> Extracting text blocks and tool use blocks from the response.</li><li><strong>Streaming:</strong> Processing server-sent events for real-time output.</li><li><strong>Error handling:</strong> Retrying on rate limits, handling network failures, and managing API-specific errors.</li></ul><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>If you&#39;ve used the <code>anthropic</code> or <code>openai</code> Python SDK, you&#39;ve already interacted with this layer from the client side. In Python, you might write <code>client.messages.create(model=&quot;claude-sonnet-4-20250514&quot;, messages=messages, tools=tools)</code>. The agent&#39;s LLM integration layer wraps this call with conversation management, streaming handling, and tool schema generation. It&#39;s the same API call, but embedded in a larger system.</p></div><h2 id="component-3-the-tool-system" tabindex="-1">Component 3: The Tool System <a class="header-anchor" href="#component-3-the-tool-system" aria-label="Permalink to &quot;Component 3: The Tool System&quot;">​</a></h2><p>Every agent provides the model with a set of tools — well-defined operations that the model can invoke to interact with the outside world. The tool system has three parts: tool <strong>definitions</strong> (what the model sees), tool <strong>dispatch</strong> (routing a tool call to the right handler), and tool <strong>execution</strong> (performing the actual operation).</p><p><strong>Tool definitions</strong> are structured descriptions that tell the model what each tool does and what parameters it accepts. These are included in the API request, typically as JSON Schema objects. A file-reading tool might be defined as having a <code>path</code> parameter (string, required) and a <code>line_range</code> parameter (object with <code>start</code> and <code>end</code> integers, optional).</p><p><strong>Tool dispatch</strong> routes a tool call from the model to the appropriate handler. The strategies differ:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Dispatch Strategy</th></tr></thead><tbody><tr><td>Claude Code</td><td>Static match on tool name</td></tr><tr><td>OpenCode</td><td>Runtime registry lookup by name</td></tr><tr><td>Pi</td><td>Trait object dispatch with name matching</td></tr><tr><td>Codex</td><td>Internal dispatch within sandbox runtime</td></tr></tbody></table><p><strong>Tool execution</strong> performs the actual operation — reading a file, writing content, running a shell command. Every agent wraps execution in error handling that converts failures into informative messages the model can reason about.</p><p>The tools themselves converge across agents. Every production coding agent includes at minimum:</p><ul><li><strong>File read</strong> — Read the contents of a file by path.</li><li><strong>File write</strong> — Create or modify a file (full replacement or diff-based).</li><li><strong>Shell execute</strong> — Run a command and capture stdout/stderr.</li><li><strong>Search/grep</strong> — Find patterns across files in the codebase.</li><li><strong>List directory</strong> — Enumerate files in a directory.</li></ul><p>Most also include additional tools for specific tasks — git operations, web search, code navigation via LSP, and sometimes specialized tools like image generation or diagram creation.</p><h2 id="component-4-context-management" tabindex="-1">Component 4: Context Management <a class="header-anchor" href="#component-4-context-management" aria-label="Permalink to &quot;Component 4: Context Management&quot;">​</a></h2><p>Language models have finite context windows. A coding agent&#39;s conversation — including system prompt, user messages, tool calls, and tool results — can easily grow to hundreds of thousands of tokens during a complex task. Every agent needs a strategy for managing this growth.</p><p>The strategies fall into a few categories:</p><p><strong>Truncation.</strong> The simplest approach: when the context gets too long, drop the oldest messages. This risks losing important early context (like the user&#39;s original request) but is easy to implement.</p><p><strong>Summarization/Compaction.</strong> Claude Code&#39;s approach: when the context grows too long, ask the model to summarize the conversation so far, then replace the detailed history with the summary. This preserves the essential information while dramatically reducing token count.</p><p><strong>Selective inclusion.</strong> Rather than including everything in the conversation, only include messages that are relevant to the current step. This requires more sophisticated logic to determine relevance but can be very token-efficient.</p><p><strong>Token counting.</strong> All strategies require knowing how many tokens the current context consumes. This involves either using the model provider&#39;s tokenizer or approximating token counts based on character/word counts.</p><p>Context management is invisible when it works and catastrophic when it doesn&#39;t. If the agent loses track of what it&#39;s been doing because important context was evicted, it might repeat work, contradict earlier decisions, or lose track of the original goal. Getting this right is one of the most important engineering challenges in agent development.</p><h2 id="component-5-safety-and-permissions" tabindex="-1">Component 5: Safety and Permissions <a class="header-anchor" href="#component-5-safety-and-permissions" aria-label="Permalink to &quot;Component 5: Safety and Permissions&quot;">​</a></h2><p>Every agent needs some mechanism to prevent dangerous operations. The approaches differ drastically — from Codex&#39;s sandbox isolation to Claude Code&#39;s tiered permission system — but the underlying need is universal.</p><p>Permission systems typically address three questions:</p><ol><li><p><strong>What operations are allowed?</strong> Some agents categorize tools by risk level (read = safe, write = needs approval, shell = dangerous). Others allow everything within a sandbox.</p></li><li><p><strong>Who decides?</strong> In interactive agents, the user approves or denies specific operations. In async agents, the sandbox provides the safety boundary. Some agents allow pre-configured allow-lists that grant blanket approval for certain operations.</p></li><li><p><strong>What happens when an operation is denied?</strong> The agent must handle denial gracefully — typically by informing the model that the operation was blocked and letting it find an alternative approach.</p></li></ol><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>The permission models reveal interesting philosophical differences. Claude Code&#39;s model trusts the user to make good decisions about what to allow. Codex&#39;s model trusts the sandbox to contain any damage. OpenCode gives users fine-grained control through configuration. Pi encodes permission checks in the type system, making it a compile-time concern rather than a runtime one. Each approach reflects a different assumption about where trust should live in the system.</p></div><h2 id="the-meta-pattern-separation-of-concerns" tabindex="-1">The Meta-Pattern: Separation of Concerns <a class="header-anchor" href="#the-meta-pattern-separation-of-concerns" aria-label="Permalink to &quot;The Meta-Pattern: Separation of Concerns&quot;">​</a></h2><p>Zooming out from the five components, the meta-pattern is <strong>separation of concerns</strong>. Every well-designed agent separates:</p><ul><li><strong>Reasoning</strong> (the model) from <strong>execution</strong> (the tools).</li><li><strong>Interface</strong> (the UI) from <strong>logic</strong> (the loop and dispatch).</li><li><strong>Provider specifics</strong> (API format, auth, streaming) from <strong>agent logic</strong> (message management, tool orchestration).</li><li><strong>Policy</strong> (what&#39;s allowed) from <strong>mechanism</strong> (how it&#39;s executed).</li></ul><p>This separation makes agents modular, testable, and adaptable. You can swap the UI without touching the loop. You can add a tool without changing the LLM integration. You can switch providers without rewriting the tool system. Each component has a clear responsibility and a well-defined interface to the others.</p><p>When we build our agent, we&#39;ll follow this separation rigorously. Each chapter in this tutorial corresponds roughly to one component, and the interfaces between components will be explicit and typed.</p><h2 id="the-blueprint-we-ll-follow" tabindex="-1">The Blueprint We&#39;ll Follow <a class="header-anchor" href="#the-blueprint-we-ll-follow" aria-label="Permalink to &quot;The Blueprint We&#39;ll Follow&quot;">​</a></h2><p>Here&#39;s how the five components map to the agent we&#39;ll build:</p><table tabindex="0"><thead><tr><th>Component</th><th>Our Implementation</th><th>Chapter(s)</th></tr></thead><tbody><tr><td>Agentic Loop</td><td>Async loop with model-driven termination</td><td>Ch 4</td></tr><tr><td>LLM Integration</td><td>Anthropic API client with streaming</td><td>Ch 3</td></tr><tr><td>Tool System</td><td>Trait-based dispatch with enum tools</td><td>Ch 5-8</td></tr><tr><td>Context Management</td><td>Token counting with compaction</td><td>Ch 9</td></tr><tr><td>Safety/Permissions</td><td>Tiered permission system</td><td>Ch 12</td></tr></tbody></table><p>This is the blueprint. Every architectural decision we make in the coming chapters traces back to the patterns we&#39;ve observed across Claude Code, OpenCode, Pi, and Codex. You&#39;re not learning arbitrary design choices — you&#39;re learning the patterns that the industry has converged on through hard-won experience.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Every production coding agent shares five core components: the agentic loop, the LLM integration layer, the tool system, context management, and a safety/permission model.</li><li>The agentic loop is model-driven, accumulative, and naturally terminating — the model decides when to call tools and when to stop, and the conversation history grows with each iteration.</li><li>Tool systems share a three-part structure (definition, dispatch, execution) but differ in dispatch strategy — from static matching to dynamic registries to trait-based dispatch.</li><li>Context management is the invisible engineering challenge that determines whether an agent can handle complex, multi-step tasks without losing coherence.</li><li>The meta-pattern across all agents is separation of concerns: reasoning from execution, interface from logic, provider specifics from agent logic, and policy from mechanism.</li></ul>`,56)])])}const g=t(a,[["render",l]]);export{m as __pageData,g as default};
